sql:
SELECT * FROM students WHERE gpa = 4.0 AND stu_id NOT IN (
    SELECT stu_id FROM grades WHERE grade = 'F'
);

SELECT stu_name, major
FROM students
WHERE gpa > (SELECT AVG(gpa) FROM students);

SELECT instructor_name, department, title
FROM instructors
WHERE instructor_id > 5;

external_knowledge:
- 'guiding stars' metaphorically refers to advisors;
- 'embarked on their academic journeys' metaphorically refers to the enrollment in courses;
- 'mentorship' refers to the advisor-student relationship, starting from the `start_date`;
- 'course enrollment' refers to the date a student joins a course, `enrollment_date`.

sql:
SELECT stu_name
FROM students
WHERE stu_id IN (
  SELECT instructor_id
  FROM instructors
) AND role = 'instructor';

SELECT stu_id, stu_name, gpa
FROM students
WHERE gpa > (SELECT AVG(gpa) FROM students);

SELECT stu_id, stu_name, email, role 
FROM students 
WHERE role IN ('instructor', 'advisor');

SELECT DISTINCT s.stu_id, s.stu_name, s.email 
FROM students s 
JOIN student_advisors sa ON s.stu_id = sa.stu_id;

SELECT COUNT(DISTINCT stu_id) 
FROM transcripts 
WHERE grade = 'A';

external_knowledge:
- 'certain student' refers to the individual with the unique student identifier provided in the query;
- 'this semester' refers to the specified semester in the query;
- 'academic profile' includes the major, cumulative GPA, courses taken, instructors, and grades achieved by the student.

sql:
SELECT major, AVG(gpa) AS average_gpa
FROM students
GROUP BY major;

SELECT DISTINCT stu_id, stu_name
FROM students
WHERE role IN ('instructor', 'advisor');

SELECT COUNT(*)
FROM instructors
WHERE instructor_id IN (SELECT advisor_id FROM advisors);

SELECT stu_id, advisor_id
FROM student_advisors
WHERE end_date IS NULL;
